// Build URL based on entry/output status
const row = $input.first().json;
const ccId = row.cc_id;
const entryRunned = row.entries_runned;
const outputRunned = row.outputs_runned;

// Get current date in dd/mm/yyyy format (Brazil timezone)
const now = new Date();
const day = String(now.getDate()).padStart(2, '0');
const month = String(now.getMonth() + 1).padStart(2, '0');
const year = now.getFullYear();
const currentDate = `${day}/${month}/${year}`;

// Determine type and URL
let type, urlType;
if (entryRunned === 0) {
  type = 'entrada';
  urlType = 'Entrada';
} else if (outputRunned === 0) {
  type = 'saida';
  urlType = 'Saida';
} else {
  // Fallback (should not happen due to WHERE clause)
  type = 'entrada';
  urlType = 'Entrada';
}

// Build VHSYS URL
const url = `https://app.vhsys.com.br/Relatorio/Relatorio.CentroCustos.JSON.php?considerarData=pagamento&Data1=01/01/2002&Data2=${currentDate}&ListarCentroAtivoSemLancamento=1&modelo=2&Nome=&Cod=&Tipo=${urlType}&Centro=${ccId}&Categoria=null&buscar=1`;

// Structured logging (without sensitive URL params)
console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'cc_next_url_generated',
  cc_id: ccId,
  type: type,
  entry_runned: entryRunned,
  output_runned: outputRunned
}));

return {
  statusCode: 200,
  body: {
    url: url,
    cc_id: ccId,
    type: type
  }
};

// No pending CCs found
console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'cc_next_url_no_pending',
  level: 'warn'
}));

return {
  statusCode: 200,
  body: {
    url: null,
    cc_id: null,
    type: null,
    message: 'No pending CCs found (all entries and outputs completed)'
  }
};
